INSERT INTO products (id, url, name, price, original_price, category, brand, rating, review_count, stock, description, images, specs, reviews, embedding) VALUES ('698d88579e285fcfc4caa0dc', 'https://www.thegioididong.com/dtdd/honor-x9d-5g-12gb-256gb', 'Điện thoại HONOR X9d 5G 12GB/256GB', 10990000, 1470000, 'phone', 'HONOR', 0, 2, 25, 'Điện thoại HONOR X9d 5G 12GB/256GB', '["https://cdn.tgdd.vn/Products/Images/42/358683/honor-x9d-5g-do-thumb-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/42/358672/vivo-y21d-purple-thumb-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/42/358669/vivo-y21d-purple-thumb-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/42/358668/vivo-y21d-black-thumb-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/7077/358457/dong-ho-dinh-vi-tre-em-imoo-z3-xanh-thumb-1-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/58/248328/cap-type-c-20cm-xmobile-tc200b-avatar1-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/57/316203/sac-du-phong-10000mah-magnetic-typecpd-30w-baseus-ppcxm10t-kem-cap-type-c-thumb-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/57/310234/sac-du-phong-10000mah-typecpd-22-5w-baseus-ppmd10-cap-lightning-va-typec-thumb-2-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/57/327846/sac-du-phong-polymer-10000mah-type-c-pd-30w-baseus-free2pull-ppss1030-kem-cap-type-c-thumb-1-600x600.jpg", "https://cdn.tgdd.vn/Products/Images/9499/271813/adapter-sac-usb-type-c-pd-65w-samsung-ep-t6530n-thumb-600x600.jpeg"]', '[{"label": "Android 15", "value": "Android 15"}, {"label": "Chip x\u1eed l\u00fd (CPU):", "value": "Snapdragon 6 Gen 4 8 nh\u00e2n"}, {"label": "1 nh\u00e2n 2.3 GHz, 3 nh\u00e2n 2.2 GHz & 4 nh\u00e2n 1.8 GHz", "value": "1 nh\u00e2n 2.3 GHz, 3 nh\u00e2n 2.2 GHz & 4 nh\u00e2n 1.8 GHz"}, {"label": "Chip \u0111\u1ed3 h\u1ecda (GPU):", "value": "Adreno A810"}, {"label": "12 GB", "value": "12 GB"}, {"label": "Dung l\u01b0\u1ee3ng l\u01b0u tr\u1eef:", "value": "256 GB"}, {"label": "Dung l\u01b0\u1ee3ng c\u00f2n l\u1ea1i (kh\u1ea3 d\u1ee5ng) kho\u1ea3ng:", "value": "236 GB"}, {"label": "Danh b\u1ea1:", "value": "Kh\u00f4ng gi\u1edbi h\u1ea1n"}, {"label": "Ch\u00ednh 108 MP & Ph\u1ee5 5 MP", "value": "Ch\u00ednh 108 MP & Ph\u1ee5 5 MP"}, {"label": "16 MP", "value": "16 MP"}, {"label": "T\u00ednh n\u0103ng camera tr\u01b0\u1edbc:", "value": "Ph\u1ea3n chi\u1ebfu g\u01b0\u01a1ng"}, {"label": "1.5K (1200 x 2640 Pixels)", "value": "1.5K (1200 x 2640 Pixels)"}, {"label": "M\u00e0n h\u00ecnh r\u1ed9ng:", "value": "6.79\" - T\u1ea7n s\u1ed1 qu\u00e9t 120 Hz"}, {"label": "6000 nits", "value": "6000 nits"}, {"label": "M\u1eb7t k\u00ednh c\u1ea3m \u1ee9ng:", "value": "K\u00ednh c\u01b0\u1eddng l\u1ef1c Corning Gorilla Glass Victus 2"}, {"label": "Dung l\u01b0\u1ee3ng pin:", "value": "8300 mAh"}, {"label": "Lo\u1ea1i pin:", "value": "Silicon-Carbon"}, {"label": "H\u1ed7 tr\u1ee3 s\u1ea1c t\u1ed1i \u0111a:", "value": "66 W"}, {"label": "S\u1ea1c k\u00e8m theo m\u00e1y:", "value": "66 W"}, {"label": "Kh\u00e1ng n\u01b0\u1edbc, b\u1ee5i:", "value": "IP66, IP68, IP69, IP69K"}, {"label": "Ghi \u00e2m:", "value": "Ghi \u00e2m cu\u1ed9c g\u1ecdi"}, {"label": "Radio:", "value": "C\u00f3"}, {"label": "Xem phim:", "value": "AVI"}, {"label": "Nghe nh\u1ea1c:", "value": "MKV"}, {"label": "AGPS", "value": "AGPS"}, {"label": "Ch\u1ea5t li\u1ec7u:", "value": "Khung & M\u1eb7t l\u01b0ng nh\u1ef1a"}, {"label": "K\u00edch th\u01b0\u1edbc, kh\u1ed1i l\u01b0\u1ee3ng:", "value": "D\u00e0i 161.9 mm - Ngang 76.1 mm - D\u00e0y 7.76 mm - N\u1eb7ng 193 g"}, {"label": "Th\u1eddi \u0111i\u1ec3m ra m\u1eaft:", "value": "12/2025"}, {"label": "H\u00e3ng:", "value": "HONOR. Xem th\u00f4ng tin h\u00e3ng"}]', '[{"content": "M\u00e1y s\u00e0i r\u1ea5t t\u1ed1t, pin tr\u00e2u, m\u00e0n h\u00ecnh r\u1ea5t \u0111\u1eb9p vi\u1ec1n m\u1ecfng kh\u00f4ng r\u1ef1c b\u1eb1ng SS nh\u01b0ng vi\u1ec1n m\u1ecfng h\u01a1n r\u1ea5t nhi\u1ec1u, c\u00f3 ch\u1ebf \u0111\u1ed9 b\u1ea3o v\u1ec7 m\u1eaft PWM, ch\u1ee5p \u1ea3nh c\u0169ng \u0111\u1eb9p do d\u00f9ng c\u1ea3m bi\u1ebfn HM6 108Mpx c\u1ee7a Samsung, s\u1ea1c nhanh 66w, s\u00f3ng 5G kh\u1ecfe, c\u1ea5u h\u00ecnh c\u0169ng m\u1ea1nh \u0111\u1ee7 d\u00f9ng. \u0110i\u1ec3m tr\u1eeb con n\u00e0y m\u00e0u \u0111en/ \u0111\u1ecf b\u00f3ng l\u00e0 vi\u1ec1n b\u00f3ng r\u1ea5t d\u1ec5 b\u00e1m v\u00e2n tay, n\u1ebfu mua m\u00e0u v\u00e0ng th\u00ec vi\u1ec1n nh\u00e1m s\u1ebd \u00edt h\u01a1n, Nh\u00e2n vi\u00ean TGDD r\u1ea5t nhi\u1ec7t t\u00ecnh, h\u1eadu m\u00e3i t\u1ed1t, c\u00f3 thu c\u0169 \u0111\u1ed5i m\u1edbi sau n\u00e0y mu\u1ed1n l\u00ean \u0111\u1eddi, h\u1ed7 tr\u1ee3 t\u1eadn nhi\u1ec7t t\u00ecnh, m\u00ecnh mua TGDD v\u00ec nh\u1eefng \u0111i\u1ec1u tr\u00ean, ch\u01b0a k\u1ec3 B\u1ea3o h\u00e0nh Honor ch\u1ec9 c\u00f3 4 trung t\u00e2m c\u1ea3 n\u01b0\u1edbc, mua \u1edf n\u01a1i kh\u00e1c gi\u00e1 t\u1ed1t h\u01a1n nh\u01b0ng g\u1eb7p v\u1ea5n \u0111\u1ec1 ph\u1ea3i ra t\u1edbi TTBH, mua t\u1eb7ng hay s\u1eed d\u1ee5ng n\u1ebfu ng\u01b0\u1eddi kh\u00f4ng r\u00e0nh v\u1ec1 c\u00f4ng ngh\u1ec7 c\u00f3 th\u1ec3 ra b\u1ea5t k\u1ef3 TGDD n\u00e0o c\u0169ng \u0111\u01b0\u1ee3c h\u1ed7 tr\u1ee3, \u0111\u00e1nh \u0111\u1ed5i m\u1ee9c gi\u00e1 cao b\u00f9 l\u1ea1i nh\u1eefng \u0111i\u1ec1u tr\u00eanM\u1eb9o nh\u1ecf cho m\u00e1y n\u00e0y Trong ph\u1ea7n c\u00e0i \u0111\u1eb7t pin, t\u1eaft dung l\u01b0\u1ee3ng th\u00f4ng minh, m\u00e1y s\u1ebd s\u1ea1c t\u1ed1i \u0111a 8300mAh thay v\u00ec ch\u1ec9 s\u1ea1c t\u1edbi 7500mAh l\u00e0 d\u1eebng do Honor \u00e9p xu\u1ed1ng. Pin s\u1ebd tr\u00e2u h\u01a1n, t\u1eaft v\u00e0 x\u00f3a b\u1edbt app r\u00e1c s\u1ebd m\u01b0\u1ee3t m\u00e0 h\u01a1n n\u1eefa.", "rating": 5, "date": "2026-02-12T07:59:19.186000"}, {"content": "X\u00e0i r\u1ea5t ok, ch\u1ec9 th\u1ea5y pin t\u1ee5t h\u01a1i nhanh ch\u01b0a nh\u01b0 k\u1ef3 v\u1ecdng v\u1ec1 vi\u00ean pin 8300m", "rating": 5, "date": "2026-02-12T07:59:19.186000"}]', NULL);
